import React, { useState, useMemo } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { 
  ShoppingBag, 
  LogOut, 
  Package, 
  BarChart2, 
  History, 
  ShieldCheck, 
  Search, 
  ShoppingCart, 
  User, 
  Phone, 
  ChevronDown,
  Trash2,
  Plus,
  Minus,
  X,
  UserCheck
} from 'lucide-react';

const Sales = () => {
  const navigate = useNavigate();

  const [products] = useState([
    { id: 1, name: 'Mevalar toplami', price: 45000, stock: 50, image: 'https://images.unsplash.com/photo-1610832958506-aa56368176cf?auto=format&fit=crop&q=80&w=400' },
    { id: 2, name: 'Sabzavotlar seti', price: 32000, stock: 120, image: 'https://images.unsplash.com/photo-1566385101042-1a0aa0c12e8c?auto=format&fit=crop&q=80&w=400' },
    { id: 3, name: 'Sut mahsulotlari', price: 12500, stock: 45, image: 'https://images.unsplash.com/photo-1550583724-125581fe2f8a?auto=format&fit=crop&q=80&w=400' },
  ]);

  const customers = [
    { id: 1, name: 'Ali Valiyev', phone: '+998 90 123 45 67' },
    { id: 2, name: 'Guli Anvarova', phone: '+998 93 456 78 90' },
  ];

  const [cartItems, setCartItems] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCustomer, setSelectedCustomer] = useState(null);

  const filteredProducts = useMemo(() => {
    if (!searchTerm.trim()) return [];
    return products.filter(p => p.name.toLowerCase().includes(searchTerm.toLowerCase()));
  }, [searchTerm, products]);

  const addToCart = (product) => {
    setCartItems(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    setSearchTerm('');
  };

  const updateQuantity = (id, delta) => {
    setCartItems(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const removeFromCart = (id) => setCartItems(prev => prev.filter(item => item.id !== id));

  const totalAmount = cartItems.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalItems = cartItems.reduce((sum, item) => sum + item.quantity, 0);

  const handleLogout = () => navigate('/login');

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-gray-900">
      <nav className="fixed w-full top-0 z-50 bg-white border-b border-gray-100 shadow-sm">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-8 h-full">
            <NavLink to="/products">
              <Package className="w-5 h-5" />
              <span>Mahsulotlar</span>
            </NavLink>
            <NavLink to="/sales" active>
              <BarChart2 className="w-5 h-5" />
              <span>Savdo</span>
            </NavLink>
          </div>
          <button onClick={handleLogout} className="text-gray-500 hover:text-red-600 font-semibold">
            <LogOut className="w-5 h-5 inline mr-2" /> Chiqish
          </button>
        </div>
      </nav>

      <main className="pt-32 pb-20 px-6 max-w-7xl mx-auto">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2 space-y-6">
            <div className="relative">
              <Search className="absolute left-5 top-1/2 -translate-y-1/2 w-6 h-6 text-gray-400" />
              <input 
                type="text" 
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                placeholder="Mahsulotlarni qidirish..."
                className="w-full pl-14 pr-6 py-5 rounded-[2rem] border-none shadow-md outline-none text-lg"
              />
              {filteredProducts.length > 0 && (
                <div className="absolute top-full left-0 right-0 mt-3 bg-white rounded-[2rem] shadow-xl z-40 border border-gray-100 overflow-hidden">
                  {filteredProducts.map(p => (
                    <button key={p.id} onClick={() => addToCart(p)} className="w-full flex items-center justify-between p-4 hover:bg-purple-50">
                      <div className="flex items-center gap-4">
                        <img src={p.image} alt={p.name} className="w-12 h-12 rounded-xl object-cover" />
                        <span className="font-bold">{p.name}</span>
                      </div>
                      <span className="font-black text-purple-700">{p.price.toLocaleString()} UZS</span>
                    </button>
                  ))}
                </div>
              )}
            </div>

            <div className="bg-white rounded-[2.5rem] shadow-md border border-gray-50 flex flex-col overflow-hidden">
              <div className="p-8 border-b border-gray-50 flex justify-between items-center">
                <h2 className="text-2xl font-black flex items-center gap-3">
                  <ShoppingCart className="w-7 h-7 text-purple-700" /> Savat
                </h2>
                {cartItems.length > 0 && (
                  <button onClick={() => setCartItems([])} className="text-red-500 font-bold">Tozalash</button>
                )}
              </div>
              <div className="flex-1 overflow-y-auto max-h-[450px] p-8">
                {cartItems.length === 0 ? (
                  <p className="text-center text-gray-400">Savat bo'sh</p>
                ) : (
                  <div className="space-y-4">
                    {cartItems.map((item) => (
                      <div key={item.id} className="flex items-center gap-4 p-4 bg-slate-50 rounded-3xl border hover:border-purple-100 transition-all">
                        <img src={item.image} alt={item.name} className="w-20 h-20 rounded-2xl object-cover" />
                        <div className="flex-1">
                          <h4 className="font-bold">{item.name}</h4>
                          <p className="text-purple-700 font-black">{item.price.toLocaleString()} UZS</p>
                        </div>
                        <div className="flex items-center gap-3 bg-white rounded-2xl p-1.5 shadow-sm border">
                          <button onClick={() => updateQuantity(item.id, -1)}><Minus className="w-4 h-4" /></button>
                          <span className="font-black">{item.quantity}</span>
                          <button onClick={() => updateQuantity(item.id, 1)}><Plus className="w-4 h-4" /></button>
                        </div>
                        <button onClick={() => removeFromCart(item.id)} className="text-gray-300 hover:text-red-500"><Trash2 className="w-6 h-6" /></button>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>

          <div className="space-y-6">
            <div className="bg-white rounded-[2.5rem] p-8 shadow-md">
              <h3 className="text-xl font-black mb-6 flex items-center gap-3"><User className="w-6 h-6 text-purple-700" /> Xaridor</h3>
              <select 
                onChange={(e) => setSelectedCustomer(customers.find(c => c.id === parseInt(e.target.value)) || null)}
                className="w-full bg-slate-50 border border-gray-100 rounded-2xl px-5 py-4 font-bold outline-none"
              >
                <option value="">Xaridorni tanlang...</option>
                {customers.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
              </select>
              {selectedCustomer && (
                <div className="mt-4 bg-purple-50 p-4 rounded-2xl border border-purple-100">
                  <p className="font-black text-purple-900">{selectedCustomer.name}</p>
                  <p className="text-purple-600 text-sm">{selectedCustomer.phone}</p>
                </div>
              )}
            </div>

            <div className="bg-white rounded-[2.5rem] p-8 shadow-md">
              <div className="flex justify-between items-center mb-4">
                <span className="text-gray-500 font-bold">Mahsulotlar:</span>
                <span className="font-black">{totalItems} ta</span>
              </div>
              <div className="flex justify-between items-end mb-8">
                <span className="text-gray-400 font-black uppercase text-xs">Jami summa:</span>
                <span className="text-3xl font-black text-purple-700">{totalAmount.toLocaleString()} UZS</span>
              </div>
              <button disabled={cartItems.length === 0} className="w-full py-5 rounded-2xl font-black text-xl bg-purple-700 text-white disabled:bg-gray-100 disabled:text-gray-400 transition-all shadow-lg active:scale-95">
                Savdoni yakunlash
              </button>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
};

const NavLink = ({ to, children, active = false }) => (
  <Link to={to} className={`flex items-center gap-2 px-1 h-full font-bold transition-all relative ${active ? 'text-purple-700' : 'text-gray-500'}`}>
    {children}
    {active && <div className="absolute bottom-0 left-0 right-0 h-1 bg-purple-700 rounded-t-full"></div>}
  </Link>
);

export default Sales;
